{"path":"/home/user/workspace/app/page.tsx","content":"import { revalidateTag } from 'next/cache';
import { getAllProducts, syncLatestCatalog, getCatalogCacheInfo } from '../lib/db';

export const experimental_ppr = true;

async function refreshCatalogAction() {
  'use server';

  await syncLatestCatalog();
  revalidateTag('products');
}

export default async function Page() {
  const products = await getAllProducts();
  const { cachedAt } = getCatalogCacheInfo();

  return (
    <main style={{ fontFamily: 'system-ui, sans-serif', padding: '32px', maxWidth: 960, margin: '0 auto' }}>
      <header style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 24, marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: 32, margin: '0 0 8px' }}>Admin Catalog</h1>
          <p style={{ margin: 0, color: '#555' }}>
            Browse the latest product catalog quickly. Data is cached and refreshed in the background when you sync.
          </p>
        </div>

        <form action={refreshCatalogAction}>
          <button
            type="submit"
            style={{
              border: 'none',
              background: '#111827',
              color: 'white',
              padding: '12px 16px',
              borderRadius: 8,
              cursor: 'pointer',
              fontWeight: 600
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <section style={{ marginBottom: 20, color: '#666', fontSize: 14 }}>
        <div>Cache tag: <strong>products</strong></div>
        <div>Last refreshed: {cachedAt ? new Date(cachedAt).toLocaleString() : 'Never'}</div>
      </section>

      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '1px solid #e5e7eb' }}>
              <th style={{ padding: '12px 8px' }}>SKU</th>
              <th style={{ padding: '12px 8px' }}>Product</th>
              <th style={{ padding: '12px 8px' }}>Price</th>
              <th style={{ padding: '12px 8px' }}>Inventory</th>
              <th style={{ padding: '12px 8px' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                <td style={{ padding: '12px 8px' }}>{product.id}</td>
                <td style={{ padding: '12px 8px', fontWeight: 600 }}>{product.name}</td>
                <td style={{ padding: '12px 8px' }}>${product.price}</td>
                <td style={{ padding: '12px 8px' }}>{product.inventory}</td>
                <td style={{ padding: '12px 8px' }}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}
"}

